1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const ALIKE_BLOCK_SIZE = 3;
9	const ALIKE_BLOCK_PREMIUM = 60;
10	
11	const BASE_PREMIUM: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	type Item = { type: string; cursed?: boolean; enchantment?: number };
21	type Step = { items: Item[] };
22	type Customer = { yearsWithMHPCO: number };
23	type Scenario = { customer: Customer; steps: Step[] };
24	
25	const groupByType = (items: Item[]): Item[][] => {
26	  const groups = Map.groupBy(items, (item) => item.type);
27	  return Array.from(groups.values());
28	};
29	
30	const sumBasePremiums = (items: Item[]): number =>
31	  items.reduce((acc, { type }) => acc + BASE_PREMIUM[type], 0);
32	
33	const basePremiumForGroup = (group: Item[]): number =>
34	  group.length === ALIKE_BLOCK_SIZE ? ALIKE_BLOCK_PREMIUM : sumBasePremiums(group);
35	
36	const basePremiumForItems = (items: Item[]): number =>
37	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
38	
39	const cursedSurcharge = (item: Item): number =>
40	  item.cursed ? BASE_PREMIUM[item.type] * CURSED_SURCHARGE_RATE : 0;
41	
42	const highEnchantmentSurcharge = (item: Item): number =>
43	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
44	    ? BASE_PREMIUM[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE
45	    : 0;
46	
47	const itemSurcharges = (items: Item[]): number =>
48	  items.reduce(
49	    (sum, item) => sum + cursedSurcharge(item) + highEnchantmentSurcharge(item),
50	    0,
51	  );
52	
53	const firstInsuranceSurcharge = (basePremium: number): number =>
54	  basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
55	
56	const loyaltyDiscount = (basePremium: number, customer: Customer): number =>
57	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
58	
59	const quotePremium = (items: Item[], customer: Customer): number => {
60	  const basePremium = basePremiumForItems(items);
61	  return (
62	    Math.ceil(
63	      basePremium +
64	        itemSurcharges(items) +
65	        firstInsuranceSurcharge(basePremium) -
66	        loyaltyDiscount(basePremium, customer),
67	    ) + PROCESSING_FEE
68	  );
69	};
70	
71	export const runScenario = (scenario: Scenario): unknown => {
72	  const results = scenario.steps.map((step) => ({
73	    premium: quotePremium(step.items, scenario.customer),
74	  }));
75	  return { results };
76	};
